#include<bits/stdc++.h>
using namespace std;
struct node {
	int x, y;
} a[100001];
long long n, t, ans = 0;
int main() {

	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> a[i].x >> a[i].y;
	}
	for (int i = 0; i < n; i++) {
		for (int j = 0; j < n; j++) {
			if (a[j].x == a[j + 1].x) {
				if (a[j].y < a[j + 1].y) {
					t = a[j].y;
					a[j].y = a[j + 1].y;
					a[j + 1].y = t;
                    t = a[j].x;
				a[j].x = a[j + 1].x;
				a[j + 1].x = t;
					ans++;

				}
			}
			if (a[j].x < a[j + 1].x) {
				t = a[j].x;
				a[j].x = a[j + 1].x;
				a[j + 1].x = t;
                t = a[j].y;
					a[j].y = a[j + 1].y;
					a[j + 1].y = t;
				ans++;
			}
		}
	}
	cout << ans;
}
